# E2-Skeptic three-route assess for S43-T1-A-E2
def assess(record: dict) -> str:
    required = {'lock_copied_before_source', 'digest_stable', 'dependency_layer_reused', 'source_change_rebuilds', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    try:
        ok = not (not record["dependency_layer_reused"] and record["source_change_rebuilds"] > 3)
    except Exception:
        return 'REORDER_DOCKERFILE'
    return 'PASS' if ok else 'REORDER_DOCKERFILE'

record = {"case_id": "CASO-TRU-043-1A", **{"lock_copied_before_source":True,"dependency_layer_reused":True,"source_change_rebuilds":1,"digest_stable":True}}
valid = dict(record)
invalid = dict(valid)
# adverse: invert first boolean flag if any
_flipped=False
for _k,_v in list(invalid.items()):
    if isinstance(_v,bool):
        invalid[_k]= (not _v)
        _flipped=True
        break
if not _flipped and isinstance(invalid.get('stages'), list):
    invalid['stages']=list(reversed(invalid['stages']))
elif not _flipped and 'dependencies' in invalid:
    invalid['dependencies']=[["domain","infrastructure"]]
incomplete={k:v for k,v in valid.items() if k != 'digest_stable'}
print(assess(valid), assess(invalid), assess(incomplete))

